mapper.select:
SELECT m.id, m.status, m.reimbursement_title AS title, m.business_trip_reason AS reason, m.subsidy_total AS subsidyTotal, m.creation_time AS creationTime, e.reimburser_name AS reimburserName, e.reimburser_no AS reimburserNo, d.reim_department_name AS departmentName, d.reim_department_no AS departmentNo, c.reim_company_name AS companyName, b.business_type_name AS businessTypeName FROM fk_reim_main m LEFT JOIN fk_reim_employee e ON m.reimburser_id = e.reimburser_id LEFT JOIN fk_reim_department d ON m.reim_department_id = d.reim_department_id LEFT JOIN fk_reim_company c ON m.reim_company_id = c.reim_company_id LEFT JOIN fk_business_type b ON m.business_type_id = b.business_type_id WHERE 1 = 1
AND m.id LIKE CONCAT('%', #{id}, '%')
AND m.reimbursement_title LIKE CONCAT('%', #{title}, '%')
AND m.business_trip_reason LIKE CONCAT('%', #{reason}, '%')
AND m.reim_company_id = #{companyId}
AND m.reim_department_id = #{departmentId}
AND m.reimburser_id = #{reimburserId}
AND m.business_type_id = #{businessTypeId}
ORDER BY m.creation_time DESC
